function mk(name, city, county, month, special) {
  return `${name} is one of ${county}'s most cherished market traditions — an annual ${month} gathering in ${city} where vendors and visitors from across the region come together for a day of Swedish market culture, quality goods and genuine community spirit that has sustained local commerce across generations.\n\nSweden's market tradition is among the richest in northern Europe — the knallemarknad culture of travelling merchants, local producers and community gathering creates events of genuine social and commercial significance that go far beyond simple retail. The ${city} market celebrates this tradition with the particular warmth and character of its regional community.\n\n${special || 'The market draws from a wide regional catchment, combining local residents with visitors from surrounding communities for a commercial and social gathering that reflects the best of Swedish small-town market culture.'}\n\nFor vendors, ${name} provides reliable access to a quality Swedish market audience with strong community engagement, well-organised market facilities and the loyal buyer participation that distinguishes the finest Swedish knallemarknad events from more commercial alternatives.`;
}

